import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

// 应用当前的生成步骤
export enum GenerationStep {
  SETUP = 'SETUP',
  CHARACTERS = 'CHARACTERS',
  PLOT = 'PLOT',
  CHAPTER_PLAN = 'CHAPTER_PLAN',
  WRITING = 'WRITING'
}

import { GoogleGenAI, Type, Schema } from "@google/genai";
import { Character, WorldSetting, PlotPoint, ChapterOutline } from "../types";

// 初始化 Gemini 客户端
const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

// 使用逻辑推理能力最强的模型，保证故事连贯性
const MODEL_NAME = "gemini-3-pro-preview";

/**
 * 第一步：生成角色和世界观
 */
export const generateCharactersAndWorld = async (prompt: string): Promise<{ characters: Character[], world: WorldSetting }> => {
  console.log("正在请求 Gemini 生成角色和世界观...");

  const systemInstruction = `
    你是一位顶级的网文大神，擅长编写"重生"、"系统"、"无敌流"等爽文。
    你的任务是根据用户的简单描述，设计一个极具吸引力、设定严谨但爽点十足的小说世界观和人物小传。

    要求：
    1. 主角必须有独特的金手指（Cheat）。
    2. 反派要智商在线，但最终会被主角打脸。
    3. 配角要有鲜明的性格，不能是脸谱化的工具人。
    4. 世界观要有新意（例如：赛博修仙、克苏鲁武侠等）。
  `;

  // 定义返回的 JSON 结构 Schema
  const responseSchema: Schema = {
    type: Type.OBJECT,
    properties: {
      world: {
        type: Type.OBJECT,
        properties: {
          theme: { type: Type.STRING, description: "故事主题" },
          powerSystem: { type: Type.STRING, description: "力量/升级体系" },
          rules: { type: Type.STRING, description: "世界核心运行规则" },
        },
        required: ["theme", "powerSystem", "rules"],
      },
      characters: {
        type: Type.ARRAY,
        items: {
          type: Type.OBJECT,
          properties: {
            name: { type: Type.STRING },
            role: { type: Type.STRING, enum: ["Protagonist", "Antagonist", "Support", "Mob"] },
            personality: { type: Type.STRING, description: "详细的性格描写" },
            background: { type: Type.STRING, description: "人物背景及前世经历（如果是重生）" },
            goal: { type: Type.STRING },
            cheat: { type: Type.STRING, description: "主角的金手指，其他角色可留空" },
          },
          required: ["name", "role", "personality", "background", "goal"],
        },
      },
    },
    required: ["world", "characters"],
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        systemInstruction: systemInstruction,
        responseMimeType: "application/json",
        responseSchema: responseSchema,
        temperature: 0.8, // 稍微高一点的创造性
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    console.log("角色生成完成:", text);
    return JSON.parse(text);
  } catch (error) {
    console.error("生成角色失败:", error);
    throw error;
  }
};

/**
 * 第二步：生成主线大纲
 */
export const generateMainPlot = async (world: WorldSetting, characters: Character[]): Promise<PlotPoint[]> => {
  console.log("正在请求 Gemini 生成主线大纲...");

  const charContext = characters.map(c => `${c.name} (${c.role}): ${c.background}. 性格: ${c.personality}`).join("\n");
  const worldContext = `世界: ${world.theme}. 力量体系: ${world.powerSystem}. 规则: ${world.rules}`;

  const prompt = `
    基于以下设定，生成一个扣人心弦的爽文主线大纲。

    【世界设定】
    ${worldContext}

    【人物设定】
    ${charContext}

    要求：
    1. 分为4-6个关键剧情节点（从重生开始到最终达成目标）。
    2. 节奏紧凑，要有期待感。
    3. 逻辑通顺，前后的因果关系要明确。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING, description: "阶段名称，如：重生归来、初露锋芒、生死危机、巅峰对决" },
        summary: { type: Type.STRING, description: "该阶段的核心剧情概括" },
      },
      required: ["phase", "summary"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成大纲失败:", error);
    throw error;
  }
};

/**
 * 第三步：生成具体章节细纲 (批量生成前N章)
 */
export const generateChapterOutlines = async (
  world: WorldSetting, 
  characters: Character[], 
  plot: PlotPoint[],
  count: number = 5
): Promise<ChapterOutline[]> => {
  console.log(`正在生成前 ${count} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");

  const prompt = `
    请根据主线大纲，规划前 ${count} 章的详细细纲。

    【主线大纲】
    ${plotContext}

    要求：
    1. 第一章必须是"重生"节点，要有强烈的冲突或危机感。
    2. 每一章都要有一个小的高潮或悬念（钩子）。
    3. 明确每一章的主角行动和爽点（Cool Point）。
    4. 设定每一章必须遵守的叙事规则，确保不跑题。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        chapterNumber: { type: Type.INTEGER },
        title: { type: Type.STRING },
        summary: { type: Type.STRING, description: "详细的故事梗概" },
        narrativePulse: { type: Type.STRING, description: "叙事脉络（起承转合）" },
        coolPoint: { type: Type.STRING, description: "本章核心爽点" },
        rules: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING },
          description: "本章写作时必须遵守的规则限制（如：主角不能暴露身份，必须在结尾处反转等）" 
        },
      },
      required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成细纲失败:", error);
    throw error;
  }
};

/**
 * 第四步：流式撰写章节正文
 */
export const streamChapterContent = async (
  chapterOutline: ChapterOutline,
  world: WorldSetting,
  characters: Character[],
  previousChapterSummary: string | null,
  onChunk: (text: string) => void
) => {
  console.log(`正在撰写第 ${chapterOutline.chapterNumber} 章: ${chapterOutline.title}`);

  const protagonist = characters.find(c => c.role === 'Protagonist');
  const otherChars = characters.filter(c => c.role !== 'Protagonist').map(c => `${c.name}(${c.role}, ${c.personality})`).join(", ");

  const prompt = `
    你正在撰写一部畅销重生爽文的第 ${chapterOutline.chapterNumber} 章。

    【当前章节信息】
    标题：${chapterOutline.title}
    梗概：${chapterOutline.summary}
    脉络：${chapterOutline.narrativePulse}
    爽点：${chapterOutline.coolPoint}

    【必须遵守的规则】
    ${chapterOutline.rules.map((r, i) => `${i+1}. ${r}`).join("\n")}

    【世界与人物】
    世界观：${world.theme}, ${world.powerSystem}
    主角：${protagonist?.name} (性格: ${protagonist?.personality}, 金手指: ${protagonist?.cheat})
    其他相关人物：${otherChars}

    【上一章摘要（上下文）】
    ${previousChapterSummary ? previousChapterSummary : "这是第一章，没有上文。"}

    【写作要求】
    1. **极致爽感**：情绪调动要到位，打脸要快准狠，升级要清晰。
    2. **第三人称**：紧紧围绕主角 ${protagonist?.name} 的视角。
    3. **逻辑严密**：严格按照上述【梗概】和【脉络】发展，不要偏离。
    4. **字数**：生成约 2000 字左右的内容。
    5. **风格**：网文风格，对话生动，节奏明快。

    开始撰写正文：
  `;

  try {
    const result = await ai.models.generateContentStream({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        // 增加思考预算，让AI在写作前先构思逻辑，减少Bug
        thinkingConfig: { thinkingBudget: 1024 }, 
      }
    });

    for await (const chunk of result) {
      const text = chunk.text;
      if (text) {
        onChunk(text);
      }
    }
  } catch (error) {
    console.error("章节撰写中断:", error);
    throw error;
  }
};

