};

/**
 * 第二步：生成主线大纲
 * 强调打脸节奏和感情线推进
 */
export const generateMainPlot = async (world: WorldSetting, characters: Character[]): Promise<PlotPoint[]> => {
  console.log("正在请求 Gemini 生成爽文主线大纲...");

  const charContext = characters.map(c => {
    let desc = `${c.name} (${c.role === 'Protagonist' ? '男主' : c.role === 'Antagonist' ? '反派' : '重要配角/女主'}): ${c.background}. 性格: ${c.personality}`;
    if (c.role === 'Support') desc += " [后宫预备/重要盟友]";
    return desc;
  }).join("\n");

  const worldContext = `世界: ${world.theme}. 力量体系: ${world.powerSystem}. 规则: ${world.rules}`;

  const prompt = `
    基于以下设定，生成一个让年轻男性读者热血沸腾的爽文主线大纲。

    【世界设定】
    ${worldContext}

    【人物设定】
    ${charContext}

    要求：
    1. **节奏紧凑**：分为 4-6 个关键大剧情节点。
    2. **核心爽点**：每个阶段必须包含"扮猪吃虎"、"人前显圣"或"强势打脸"的情节。
    3. **感情线**：必须穿插主角收服各路美女（女主）的过程，或者英雄救美、暧昧互动的情节。
    4. **目标明确**：从微末崛起，最终登顶世界巅峰，拥有无尽财富和权力。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        phase: { type: Type.STRING, description: "阶段名称，如：重生归来、校花倾心、世家震怖、登顶巅峰" },
        summary: { type: Type.STRING, description: "该阶段的核心剧情概括，包含具体的打脸对象和收服的女主" },
      },
      required: ["phase", "summary"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成大纲失败:", error);
    throw error;
  }
};

/**
 * 第三步：生成具体章节细纲 (批量生成前N章)
 * 增加"爽点"（Cool Point）的具体要求
 */
export const generateChapterOutlines = async (
  world: WorldSetting, 
  characters: Character[], 
  plot: PlotPoint[],
  count: number = 5
): Promise<ChapterOutline[]> => {
  console.log(`正在生成前 ${count} 章的细纲...`);

  const plotContext = plot.map(p => `[${p.phase}] ${p.summary}`).join("\n");
  const charContext = characters.map(c => `${c.name} (${c.role})`).join(", ");

  const prompt = `
    请根据主线大纲，规划前 ${count} 章的详细细纲。

    【主线大纲】
    ${plotContext}

    【人物】
    ${charContext}

    要求：
    1. **黄金三章法则**：
       - 第一章：必须有强烈的冲突（被退婚、被羞辱、重生节点），并结尾觉醒金手指。
       - 第二章：小试牛刀，利用金手指获得初步优势，震惊路人。
       - 第三章：第一个小高潮，打脸反派（或反派的小弟），收获第一位美女的好感。
    2. **爽点密集**：每一章都要有一个明确的"爽点"（Cool Point）或"期待感"（Hook）。
    3. **细致**：summary 字段要包含具体发生的事件，不要只写空话。
  `;

  const responseSchema: Schema = {
    type: Type.ARRAY,
    items: {
      type: Type.OBJECT,
      properties: {
        chapterNumber: { type: Type.INTEGER },
        title: { type: Type.STRING, description: "极具吸引力的标题，如：震惊全场！、校花深夜来访" },
        summary: { type: Type.STRING, description: "详细的故事梗概，包含起承转合" },
        narrativePulse: { type: Type.STRING, description: "本章的情绪脉络：压抑->爆发，或者 暧昧->推倒" },
        coolPoint: { type: Type.STRING, description: "本章核心爽点，如：一拳秒杀、女神倒贴" },
        rules: { 
          type: Type.ARRAY, 
          items: { type: Type.STRING },
          description: "写作时的注意点，如：不要太啰嗦，多描写女主腿部细节" 
        },
      },
      required: ["chapterNumber", "title", "summary", "narrativePulse", "coolPoint", "rules"],
    },
  };

  try {
    const response = await ai.models.generateContent({
      model: MODEL_NAME,
      contents: prompt,
      config: {
        responseMimeType: "application/json",
        responseSchema: responseSchema,
      },
    });

    const text = response.text;
    if (!text) throw new Error("API 返回为空");
    return JSON.parse(text);
  } catch (error) {
    console.error("生成细纲失败:", error);
    throw error;
  }
};

/**
 * 第四步：流式生成章节正文
 * 核心：极致的爽文文风，注重感官刺激
 */
export const streamChapterContent = async (
  chapter: ChapterOutline,
  world: WorldSetting,
  characters: Character[],
  prevSummary: string | null,
  onChunk: (text: string) => void
): Promise<void> => {
  console.log(`正在流式生成第 ${chapter.chapterNumber} 章正文...`);

  const charContext = characters.map(c => {
    let t = `${c.name}: ${c.personality}, ${c.background}`;
    if (c.role === 'Support') t += " (重点描写对象：外貌、身材、气味)";
    return t;
  }).join("\n");

  const prompt = `
    你现在是全网最火的爽文作家。请根据以下大纲撰写第 ${chapter.chapterNumber} 章的正文。

    【章节信息】
    标题：${chapter.title}
    梗概：${chapter.summary}
    爽点：${chapter.coolPoint}
    核心规则：${chapter.rules.join(", ")}

    【上下文】
    上一章剧情：${prevSummary || "这是第一章，直接开始"}

    【世界与人物】
    世界风格：${world.theme}
    人物设定：
    ${charContext}

    【写作要求】
    1. **文风**：小白文风格，短句为主，节奏极快。不要文青，不要谜语人。
    2. **感官描写**：
       - 对女性角色：重点描写身材（长腿、细腰、曲线）、五官、声音（娇喘、冷哼）和气味（体香）。
       - 对打脸情节：描写反派的嚣张嘴脸（前）和震惊、恐惧的表情（后），形成强烈对比。
       - 对路人反应：要有大量的"倒吸一口凉气"、"目瞪口呆"等侧面描写来衬托主角的牛逼。
    3. **对话**：要口语化，装逼台词要够硬，撩妹台词要够骚。
    4. **字数**：2000字左右。
    5. **排版**：段落之间空一行，方便手机阅读。
  `;

  try {
    const responseStream = await ai.models.generateContentStream({
      model: MODEL_NAME,
      contents: prompt,
    });

    for await (const chunk of responseStream) {
      const text = chunk.text();
      if (text) {
        onChunk(text);
      }
    }
  } catch (error) {
    console.error("正文生成流中断:", error);
    throw error;
  }
};

import React, { useState, useEffect } from 'react';
import { Character, WorldSetting } from '../types';
import { User, Shield, Zap, Globe, ArrowRight, Copy, Check, Trash2 } from 'lucide-react';

interface Props {
  world: WorldSetting;
  characters: Character[];
  onConfirm: (updatedWorld: WorldSetting, updatedCharacters: Character[]) => void;
  isLoading: boolean;
}

const CopyBtn = ({ text, className = "" }: { text: string, className?: string }) => {
  const [copied, setCopied] = useState(false);

  const handleCopy = (e: React.MouseEvent) => {
    e.stopPropagation();
    navigator.clipboard.writeText(text);
    setCopied(true);
    setTimeout(() => setCopied(false), 2000);
  };

  return (
    <button 
      onClick={handleCopy} 
      className={`ml-2 p-1.5 rounded-md hover:bg-gray-700/50 transition-colors inline-flex items-center justify-center shrink-0 ${copied ? 'text-green-400' : 'text-gray-500 hover:text-indigo-400'} ${className}`}
      title="复制内容"
    >
      {copied ? <Check size={14} /> : <Copy size={14} />}
    </button>
  );
};

const StepCharacters: React.FC<Props> = ({ world, characters, onConfirm, isLoading }) => {
  const [editableWorld, setEditableWorld] = useState<WorldSetting>(world);
  const [editableCharacters, setEditableCharacters] = useState<Character[]>(characters);

  // 当外部传入的 world 或 characters 发生变化时（例如重新生成），同步更新本地状态
  useEffect(() => {
    setEditableWorld(world);
    setEditableCharacters(characters);
  }, [world, characters]);

  const handleWorldChange = (field: keyof WorldSetting, value: string) => {
    setEditableWorld(prev => ({ ...prev, [field]: value }));
  };

  const handleDeleteCharacter = (index: number) => {
    if (window.confirm("确定要删除这个角色吗？")) {
      setEditableCharacters(prev => prev.filter((_, i) => i !== index));
    }
  };

  return (
    <div className="w-full max-w-6xl mx-auto space-y-8 pb-12">
      <div className="flex justify-between items-center border-b border-gray-800 pb-4">
        <h2 className="text-2xl font-bold text-white flex items-center gap-2">
          <Globe className="text-indigo-400" />
          世界观与人物设定
        </h2>
        <button
          onClick={() => onConfirm(editableWorld, editableCharacters)}
          disabled={isLoading}
          className="px-6 py-2 bg-green-600 hover:bg-green-500 text-white font-semibold rounded-lg flex items-center gap-2 transition-all disabled:opacity-50"
        >
          {isLoading ? '生成大纲中...' : '确认并生成大纲'}
          {!isLoading && <ArrowRight size={18} />}
        </button>
      </div>

      {/* 世界观卡片 */}
      <div className="bg-gray-850 rounded-xl border border-gray-700 p-6 shadow-lg">
        <div className="mb-4">
           <label className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1 block">世界主题</label>
           <div className="flex items-center gap-2">
             <Zap size={20} className="text-indigo-400 shrink-0" />
             <input 
                type="text"
                value={editableWorld.theme}
                onChange={(e) => handleWorldChange('theme', e.target.value)}
                className="bg-transparent border-b border-gray-600 focus:border-indigo-500 outline-none text-xl font-bold text-indigo-300 w-full transition-colors pb-1"
                placeholder="输入故事主题..."
             />
             <CopyBtn text={`主题：${editableWorld.theme}\n体系：${editableWorld.powerSystem}\n规则：${editableWorld.rules}`} />
           </div>
        </div>

        <div className="grid md:grid-cols-2 gap-6">
          <div>
            <span className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-2">力量体系</span>
            <div className="flex items-start gap-2">
              <textarea 
                value={editableWorld.powerSystem}
                onChange={(e) => handleWorldChange('powerSystem', e.target.value)}
                className="w-full bg-gray-900/50 border border-gray-700 rounded-lg p-3 text-gray-300 focus:border-indigo-500 outline-none resize-none h-32 text-sm leading-relaxed transition-all focus:ring-1 focus:ring-indigo-500/50"
                placeholder="描述这个世界的力量等级和修炼方式..."
              />
              <CopyBtn text={editableWorld.powerSystem} />
            </div>
          </div>
          <div>
            <span className="text-xs font-bold text-gray-500 uppercase tracking-wider block mb-2">核心规则</span>
            <div className="flex items-start gap-2">
              <textarea 
                value={editableWorld.rules}
                onChange={(e) => handleWorldChange('rules', e.target.value)}
                className="w-full bg-gray-900/50 border border-gray-700 rounded-lg p-3 text-gray-300 focus:border-indigo-500 outline-none resize-none h-32 text-sm leading-relaxed transition-all focus:ring-1 focus:ring-indigo-500/50"
                placeholder="描述这个世界的运行规则和禁忌..."
              />
              <CopyBtn text={editableWorld.rules} />
            </div>
          </div>
        </div>
      </div>

      {/* 角色列表 */}
      <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-3 gap-6">
        {editableCharacters.map((char, idx) => (
          <div 
            key={idx} 
            className={`relative rounded-xl border p-5 shadow-md flex flex-col gap-3 group/card
              ${char.role === 'Protagonist' 
                ? 'bg-indigo-900/20 border-indigo-500/50' 
                : char.role === 'Antagonist'
                  ? 'bg-red-900/10 border-red-500/30'
                  : 'bg-gray-850 border-gray-700'
              }`}
          >
            {/* 删除按钮：主角不能删除 */}
            {char.role !== 'Protagonist' && (
              <button 
                onClick={() => handleDeleteCharacter(idx)}
                className="absolute top-3 right-3 p-1.5 rounded-full text-gray-500 hover:bg-red-900/50 hover:text-red-400 opacity-0 group-hover/card:opacity-100 transition-all z-10"
                title="删除角色"
              >
                <Trash2 size={16} />
              </button>
            )}

            <div className="flex justify-between items-start">
              <div className="flex items-center gap-1">
                <h4 className="text-lg font-bold text-white flex items-center gap-2">
                  {char.name}
                  {char.role === 'Protagonist' && <span className="text-xs bg-indigo-600 px-2 py-0.5 rounded text-white">主角</span>}
                  {char.role === 'Antagonist' && <span className="text-xs bg-red-600 px-2 py-0.5 rounded text-white">反派</span>}
                </h4>
                <CopyBtn text={`角色：${char.name}\n定位：${char.role}\n性格：${char.personality}\n目标：${char.goal}\n背景：${char.background}\n${char.cheat ? `金手指：${char.cheat}` : ''}`} className="ml-1" />
                <p className="text-sm text-gray-400 italic ml-2">{char.role === 'Support' ? '重要配角' : char.role === 'Mob' ? '路人/炮灰' : ''}</p>
              </div>
              {char.role === 'Protagonist' ? <User className="text-indigo-400" /> : <User className="text-gray-600" />}
            </div>

            <div className="space-y-2 text-sm text-gray-300 flex-grow">
              <div className="flex items-start justify-between group">
                <div>
                  <span className="text-gray-500 font-semibold mr-2">性格:</span>
                  {char.personality}
                </div>
                <CopyBtn text={char.personality} className="opacity-0 group-hover:opacity-100 transition-opacity" />
              </div>
              <div className="flex items-start justify-between group">
                 <div>
                  <span className="text-gray-500 font-semibold mr-2">目标:</span>
                  {char.goal}
                 </div>
                 <CopyBtn text={char.goal} className="opacity-0 group-hover:opacity-100 transition-opacity" />
              </div>
              <div className="group relative">
                <span className="text-gray-500 font-semibold mr-2">背景:</span>
                <span className="line-clamp-3">{char.background}</span>
                <div className="absolute top-0 right-0">
                  <CopyBtn text={char.background} className="opacity-0 group-hover:opacity-100 transition-opacity bg-gray-900/80 backdrop-blur" />
                </div>
              </div>
            </div>

            {char.cheat && (
              <div className="mt-auto pt-3 border-t border-indigo-500/30 group relative">
                <div className="text-xs text-yellow-400 font-bold flex items-center gap-1 mb-1">
                  <Shield size={12} />
                  金手指 / 能力
                </div>
                <p className="text-sm text-yellow-100/80 pr-6">{char.cheat}</p>
                <div className="absolute top-2 right-0">
                  <CopyBtn text={char.cheat} className="opacity-0 group-hover:opacity-100 transition-opacity" />
                </div>
              </div>
            )}
          </div>
        ))}
      </div>
    </div>
  );
};

export default StepCharacters;

import React, { useState, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import { Download, Upload, Save, FileJson } from 'lucide-react';

const App: React.FC = () => {
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);

  // Data State
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async (prompt: string) => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  // 接收 updatedWorld 和 updatedCharacters，保存用户的修改
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    // 更新本地状态，确保世界观和角色修改被保存
    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      // 使用更新后的世界观和角色生成大纲
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      // 默认先生成前5章
      const outlineData = await generateChapterOutlines(world, characters, plot, 5);
      // 转换为 ChapterContent 结构
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 更新章节内容的 Handler (传递给 StepWriting)
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      world,
      characters,
      plot,
      chapters
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `soulwriter-project-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        // 简单的格式校验
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    // 清空 input 允许重复导入同一文件
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer" onClick={() => setStep(GenerationStep.SETUP)}>
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
               <FileJson size={20} />
            </div>
            SoulWriter AI
          </div>

          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden md:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Import/Export Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />
              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>
              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup onGenerate={handleSetupGenerate} isLoading={isLoading} />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
}

const StepWriting: React.FC<Props> = ({ chapters, world, characters, onUpdateChapter }) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  const [showSidebar, setShowSidebar] = useState(true); // 移动端响应式侧边栏
  const [isEditing, setIsEditing] = useState(false); // 编辑模式状态

  const activeChapter = chapters[activeChapterIndex];

  // 滚动到顶部当切换章节时，并退出编辑模式
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;

    setIsGenerating(true);
    // 生成时自动退出编辑模式
    setIsEditing(false);

    // 获取上一章的摘要作为上下文
    let prevSummary = null;
    if (activeChapterIndex > 0) {
      prevSummary = chapters[activeChapterIndex - 1].outline.summary;
    }

    try {
      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevSummary,
        (textChunk) => {
          fullText += textChunk;
          // 实时更新父组件状态
          onUpdateChapter(activeChapterIndex, fullText, false);
        }
      );

      // 完成后标记为已生成
      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950">
      {/* Sidebar Toggle for Mobile */}
      <button 
        className="md:hidden fixed bottom-4 right-4 z-50 bg-indigo-600 p-3 rounded-full shadow-lg"
        onClick={() => setShowSidebar(!showSidebar)}
      >
        {showSidebar ? <X /> : <Menu />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-80 bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200">
          目录 ({chapters.length}章)
        </div>
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <button
              key={idx}
              onClick={() => {
                setActiveChapterIndex(idx);
                if (window.innerWidth < 768) setShowSidebar(false);
              }}
              className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2
                ${activeChapterIndex === idx 
                  ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                  : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
              `}
            >
              <div className="mt-0.5">
                {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
              </div>
              <div>
                <div className="font-semibold line-clamp-1">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                <div className="text-xs text-gray-500 mt-1 line-clamp-1">{chap.outline.coolPoint}</div>
              </div>
            </button>
          ))}
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative">
        {/* Info Header */}
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div>
             <h3 className="text-sm font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto">
            {/* Edit Toggle Button - 只在有内容且未生成时显示 */}
            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    完成编辑
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    修改正文
                  </>
                )}
              </button>
            )}

            {/* Generate Button - 只在内容为空时显示 */}
            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap"
              >
                {isGenerating ? 'AI写作中...' : '生成正文'}
                {!isGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Reader / Editor */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8 bg-black/20">
          <div className="max-w-3xl mx-auto h-full">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-6 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-2 border-b border-gray-800 text-gray-500 text-sm flex justify-between select-none">
                    <span>正在编辑: 第{activeChapter.outline.chapterNumber}章 {activeChapter.outline.title}</span>
                    <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                      {activeChapter.content.length} 字
                    </span>
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} // 只要编辑过，就视为已生成/有效
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 {/* Next Chapter Guide */}
                 {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                   <div className="mt-12 text-center pb-8">
                     <button
                       onClick={() => setActiveChapterIndex(prev => prev + 1)}
                       className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4"
                     >
                       继续下一章
                     </button>
                   </div>
                 )}
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

