<files>
  <file path="App.tsx">
    <![CDATA[
import React, { useState, useEffect } from 'react';
import ChapterOutline from './components/ChapterOutline';
import ChapterContent from './components/ChapterContent';
import StepWriting from './components/StepWriting';
import { initialChapters } from './data/initialChapters';
import { initialWorld } from './data/initialWorld';
import { initialCharacters } from './data/initialCharacters';
import { saveToLocalStorage, getFromLocalStorage } from './utils/localStorage';
import { ChapterContent, WorldSetting, Character } from './types';
import './App.css';

function App() {
  const [chapters, setChapters] = useState<ChapterContent[]>(() => {
    const savedChapters = getFromLocalStorage('chapters');
    return savedChapters !== null ? JSON.parse(savedChapters) : initialChapters;
  });
  const [world, setWorld] = useState<WorldSetting>(() => {
    const savedWorld = getFromLocalStorage('world');
    return savedWorld !== null ? JSON.parse(savedWorld) : initialWorld;
  });
  const [characters, setCharacters] = useState<Character[]>(() => {
    const savedCharacters = getFromLocalStorage('characters');
    return savedCharacters !== null ? JSON.parse(savedCharacters) : initialCharacters;
  });
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);

  useEffect(() => {
    saveToLocalStorage('chapters', JSON.stringify(chapters));
    saveToLocalStorage('world', JSON.stringify(world));
    saveToLocalStorage('characters', JSON.stringify(characters));
  }, [chapters, world, characters]);

  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prevChapters =>
      prevChapters.map((chapter, i) =>
        i === index ? { ...chapter, content, isGenerated } : chapter
      )
    );
  };

