/**
 * 第四步：流式生成章节正文
 * 核心：极致的爽文文风，注重感官刺激
 */
export const streamChapterContent = async (
  chapter: ChapterOutline,
  world: WorldSetting,
  characters: Character[],
  prevSummary: string | null,
  onChunk: (text: string) => void
): Promise<void> => {
  console.log(`正在流式生成第 ${chapter.chapterNumber} 章正文...`);

  const charContext = characters.map(c => {
    let t = `${c.name}: ${c.personality}, ${c.background}`;
    if (c.role === 'Support') t += " (重点描写对象：外貌、身材、气味)";
    return t;
  }).join("\n");

  const prompt = `
    你现在是全网最火的爽文作家。请根据以下大纲撰写第 ${chapter.chapterNumber} 章的正文。

    【章节信息】
    标题：${chapter.title}
    梗概：${chapter.summary}
    爽点：${chapter.coolPoint}
    核心规则：${chapter.rules.join(", ")}

    【上下文】
    上一章剧情：${prevSummary || "这是第一章，直接开始"}

    【世界与人物】
    世界风格：${world.theme}
    人物设定：
    ${charContext}

    【写作要求】
    1. **文风**：小白文风格，短句为主，节奏极快。不要文青，不要谜语人。
    2. **感官描写**：
       - 对女性角色：重点描写身材（长腿、细腰、曲线）、五官、声音（娇喘、冷哼）和气味（体香）。
       - 对打脸情节：描写反派的嚣张嘴脸（前）和震惊、恐惧的表情（后），形成强烈对比。
       - 对路人反应：要有大量的"倒吸一口凉气"、"目瞪口呆"等侧面描写来衬托主角的牛逼。
    3. **对话**：要口语化，装逼台词要够硬，撩妹台词要够骚。
    4. **字数**：2000字左右。
    5. **排版**：段落之间空一行，方便手机阅读。
  `;

  try {
    const responseStream = await ai.models.generateContentStream({
      model: MODEL_NAME,
      contents: prompt,
    });

    for await (const chunk of responseStream) {
      const text = chunk.text();
      if (text) {
        onChunk(text);
      }
    }
  } catch (error) {
    console.error("正文生成流中断:", error);
    throw error;
  }
};

import React, { useState, useRef } from 'react';
import { GenerationStep, Character, WorldSetting, PlotPoint, ChapterContent, ProjectData } from './types';
import { generateCharactersAndWorld, generateMainPlot, generateChapterOutlines, generateNextChapterOutlines } from './services/geminiService';
import StepSetup from './components/StepSetup';
import StepCharacters from './components/StepCharacters';
import StepPlot from './components/StepPlot';
import StepWriting from './components/StepWriting';
import { Download, Upload, Save, FileJson } from 'lucide-react';

const App: React.FC = () => {
  const [step, setStep] = useState<GenerationStep>(GenerationStep.SETUP);
  const [isLoading, setIsLoading] = useState(false);

  // Data State
  const [world, setWorld] = useState<WorldSetting | null>(null);
  const [characters, setCharacters] = useState<Character[]>([]);
  const [plot, setPlot] = useState<PlotPoint[]>([]);
  const [chapters, setChapters] = useState<ChapterContent[]>([]);

  const fileInputRef = useRef<HTMLInputElement>(null);

  // Step 1 -> 2: Setup to Characters
  const handleSetupGenerate = async (prompt: string) => {
    setIsLoading(true);
    try {
      const data = await generateCharactersAndWorld(prompt);
      setWorld(data.world);
      setCharacters(data.characters);
      setStep(GenerationStep.CHARACTERS);
    } catch (e) {
      alert("生成失败，请检查API Key或重试");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 2 -> 3: Characters to Plot
  // 接收 updatedWorld 和 updatedCharacters，保存用户的修改
  const handleConfirmCharacters = async (updatedWorld: WorldSetting, updatedCharacters: Character[]) => {
    if (!updatedWorld || updatedCharacters.length === 0) return;

    // 更新本地状态，确保世界观和角色修改被保存
    setWorld(updatedWorld);
    setCharacters(updatedCharacters);

    setIsLoading(true);
    try {
      // 使用更新后的世界观和角色生成大纲
      const data = await generateMainPlot(updatedWorld, updatedCharacters);
      setPlot(data);
      setStep(GenerationStep.PLOT);
    } catch (e) {
      alert("生成大纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // Step 3 -> 4: Plot to Chapter Outlines -> Writing
  const handleConfirmPlot = async () => {
    if (!world || characters.length === 0 || plot.length === 0) return;
    setIsLoading(true);
    try {
      // 默认先生成前5章
      const outlineData = await generateChapterOutlines(world, characters, plot, 5);
      // 转换为 ChapterContent 结构
      const initialChapters: ChapterContent[] = outlineData.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));
      setChapters(initialChapters);
      setStep(GenerationStep.WRITING);
    } catch (e) {
      alert("生成细纲失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 续写后续章节 (StepWriting 调用)
  const handleAddChapters = async (count: number = 5) => {
    if (!world || characters.length === 0 || plot.length === 0 || chapters.length === 0) return;

    setIsLoading(true);
    try {
      const lastChapter = chapters[chapters.length - 1];
      const newOutlines = await generateNextChapterOutlines(world, characters, plot, lastChapter.outline, count);

      const newChapters: ChapterContent[] = newOutlines.map(o => ({
        outline: o,
        content: '',
        isGenerated: false
      }));

      setChapters(prev => [...prev, ...newChapters]);
    } catch (e) {
      console.error(e);
      alert("续写章节失败");
    } finally {
      setIsLoading(false);
    }
  };

  // 更新章节内容的 Handler (传递给 StepWriting)
  const handleUpdateChapter = (index: number, content: string, isGenerated: boolean) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          content,
          isGenerated
        };
      }
      return newChapters;
    });
  };

  // 更新章节标题的 Handler
  const handleUpdateChapterTitle = (index: number, title: string) => {
    setChapters(prev => {
      const newChapters = [...prev];
      if (newChapters[index]) {
        newChapters[index] = {
          ...newChapters[index],
          outline: {
            ...newChapters[index].outline,
            title
          }
        };
      }
      return newChapters;
    });
  };

  // 导出项目
  const handleExport = () => {
    const data: ProjectData = {
      version: 1,
      step,
      world,
      characters,
      plot,
      chapters
    };

    const jsonString = JSON.stringify(data, null, 2);
    const blob = new Blob([jsonString], { type: "application/json" });
    const url = URL.createObjectURL(blob);

    const link = document.createElement('a');
    link.href = url;
    link.download = `soulwriter-project-${new Date().toISOString().slice(0, 10)}.json`;
    document.body.appendChild(link);
    link.click();
    document.body.removeChild(link);
    URL.revokeObjectURL(url);
  };

  // 导入项目触发
  const triggerImport = () => {
    fileInputRef.current?.click();
  };

  // 处理文件读取
  const handleImport = (e: React.ChangeEvent<HTMLInputElement>) => {
    const file = e.target.files?.[0];
    if (!file) return;

    const reader = new FileReader();
    reader.onload = (event) => {
      try {
        const json = JSON.parse(event.target?.result as string);
        // 简单的格式校验
        if (json.version && json.step) {
          const data = json as ProjectData;
          setStep(data.step);
          setWorld(data.world);
          setCharacters(data.characters);
          setPlot(data.plot);
          setChapters(data.chapters);
          alert("项目导入成功！");
        } else {
          alert("无效的项目文件格式");
        }
      } catch (error) {
        console.error("Import error", error);
        alert("文件解析失败");
      }
    };
    reader.readAsText(file);
    // 清空 input 允许重复导入同一文件
    e.target.value = ''; 
  };

  return (
    <div className="min-h-screen bg-[#0d1117] text-gray-100 font-sans selection:bg-indigo-500/30">
      <header className="border-b border-gray-800 bg-[#0d1117]/80 backdrop-blur sticky top-0 z-50">
        <div className="max-w-7xl mx-auto px-4 h-16 flex items-center justify-between">
          <div className="font-bold text-xl tracking-tight bg-gradient-to-r from-indigo-400 to-cyan-400 bg-clip-text text-transparent flex items-center gap-2 cursor-pointer" onClick={() => setStep(GenerationStep.SETUP)}>
            <div className="w-8 h-8 rounded-lg bg-indigo-600 flex items-center justify-center text-white">
               <FileJson size={20} />
            </div>
            SoulWriter AI
          </div>

          <div className="flex items-center gap-4">
            {/* Steps Indicator (Desktop) */}
            <div className="hidden md:flex gap-2 text-xs font-mono text-gray-500 mr-4">
              <span className={step === GenerationStep.SETUP ? 'text-indigo-400' : ''}>01.设定</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.CHARACTERS ? 'text-indigo-400' : ''}>02.人物</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.PLOT ? 'text-indigo-400' : ''}>03.大纲</span>
              <span>&gt;</span>
              <span className={step === GenerationStep.WRITING ? 'text-indigo-400' : ''}>04.正文</span>
            </div>

            {/* Import/Export Actions */}
            <div className="flex items-center gap-2 border-l border-gray-700 pl-4">
              <input 
                type="file" 
                ref={fileInputRef} 
                className="hidden" 
                accept=".json" 
                onChange={handleImport}
              />
              <button 
                onClick={triggerImport}
                className="p-2 text-gray-400 hover:text-white hover:bg-gray-800 rounded-lg transition-colors flex items-center gap-2 text-sm"
                title="导入项目"
              >
                <Upload size={18} />
                <span className="hidden sm:inline">导入</span>
              </button>
              <button 
                onClick={handleExport}
                className="px-3 py-1.5 bg-gray-800 hover:bg-gray-700 text-indigo-300 border border-indigo-500/30 rounded-lg transition-colors flex items-center gap-2 text-sm font-medium"
                title="导出项目"
              >
                <Save size={18} />
                <span className="hidden sm:inline">保存</span>
              </button>
            </div>
          </div>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8">
        {step === GenerationStep.SETUP && (
          <StepSetup onGenerate={handleSetupGenerate} isLoading={isLoading} />
        )}

        {step === GenerationStep.CHARACTERS && world && (
          <StepCharacters 
            world={world} 
            characters={characters} 
            onConfirm={handleConfirmCharacters}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.PLOT && (
          <StepPlot 
            plot={plot}
            onConfirm={handleConfirmPlot}
            isLoading={isLoading}
          />
        )}

        {step === GenerationStep.WRITING && world && (
          <StepWriting 
            chapters={chapters}
            world={world}
            characters={characters}
            onUpdateChapter={handleUpdateChapter}
            onUpdateTitle={handleUpdateChapterTitle}
            onLoadMoreChapters={handleAddChapters} // 新增 prop
            isLoadingMore={isLoading} // 复用 isLoading 来表示加载中
          />
        )}
      </main>
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ChapterContent, Character, WorldSetting } from '../types';
import { streamChapterContent } from '../services/geminiService';
import ChapterReader from './ChapterReader';
import { FileText, Play, CheckCircle, Menu, X, Edit, Save, PlusCircle, Loader2 } from 'lucide-react';

interface Props {
  chapters: ChapterContent[];
  world: WorldSetting;
  characters: Character[];
  onUpdateChapter: (index: number, content: string, isGenerated: boolean) => void;
  onUpdateTitle: (index: number, title: string) => void;
  onLoadMoreChapters: () => void; // 新增：请求加载更多章节
  isLoadingMore: boolean; // 新增：是否正在加载更多大纲
}

const StepWriting: React.FC<Props> = ({ chapters, world, characters, onUpdateChapter, onUpdateTitle, onLoadMoreChapters, isLoadingMore }) => {
  const [activeChapterIndex, setActiveChapterIndex] = useState(0);
  const [isGenerating, setIsGenerating] = useState(false);
  // 默认设为 false，移动端初始隐藏侧边栏，桌面端通过 CSS (md:translate-x-0) 保持显示
  const [showSidebar, setShowSidebar] = useState(false); 
  const [isEditing, setIsEditing] = useState(false);

  const activeChapter = chapters[activeChapterIndex];

  // 切换章节时，滚动到顶部，关闭编辑模式，如果是移动端则关闭侧边栏
  useEffect(() => {
    window.scrollTo({ top: 0, behavior: 'smooth' });
    setIsEditing(false);
  }, [activeChapterIndex]);

  const handleGenerate = async () => {
    if (isGenerating || activeChapter.isGenerated) return;

    setIsGenerating(true);
    setIsEditing(false);

    // 移动端生成开始时，自动收起侧边栏以便查看生成过程
    if (window.innerWidth < 768) {
        setShowSidebar(false);
    }

    // 获取上一章的摘要作为上下文
    let prevSummary = null;
    if (activeChapterIndex > 0) {
      prevSummary = chapters[activeChapterIndex - 1].outline.summary;
    }

    try {
      let fullText = "";
      await streamChapterContent(
        activeChapter.outline,
        world,
        characters,
        prevSummary,
        (textChunk) => {
          fullText += textChunk;
          onUpdateChapter(activeChapterIndex, fullText, false);
        }
      );

      onUpdateChapter(activeChapterIndex, fullText, true);

    } catch (e) {
      alert("生成中断，请重试");
    } finally {
      setIsGenerating(false);
    }
  };

  if (!activeChapter) return <div>数据加载中...</div>;

  return (
    <div className="flex h-[calc(100vh-100px)] overflow-hidden rounded-xl border border-gray-800 bg-gray-950 relative">

      {/* 移动端遮罩层：当侧边栏打开时显示，点击关闭 */}
      {showSidebar && (
        <div 
          className="fixed inset-0 bg-black/60 backdrop-blur-sm z-30 md:hidden transition-opacity"
          onClick={() => setShowSidebar(false)}
        />
      )}

      {/* 移动端悬浮菜单按钮 */}
      <button 
        className="md:hidden fixed bottom-6 right-6 z-50 bg-indigo-600 hover:bg-indigo-500 text-white p-4 rounded-full shadow-xl shadow-indigo-900/50 transition-all active:scale-95 flex items-center justify-center"
        onClick={() => setShowSidebar(!showSidebar)}
        title={showSidebar ? "关闭目录" : "打开目录"}
      >
        {showSidebar ? <X size={24} /> : <Menu size={24} />}
      </button>

      {/* Sidebar - Chapter List */}
      <div className={`
        fixed md:relative z-40 w-72 max-w-[80vw] bg-gray-900 border-r border-gray-800 h-full flex flex-col transition-transform duration-300 ease-in-out shadow-2xl md:shadow-none
        ${showSidebar ? 'translate-x-0' : '-translate-x-full md:translate-x-0'}
      `}>
        <div className="p-4 border-b border-gray-800 bg-gray-900 font-bold text-gray-200 flex justify-between items-center shrink-0">
          <span>目录 ({chapters.length}章)</span>
          {/* 移动端侧边栏内部关闭按钮 */}
          <button 
            onClick={() => setShowSidebar(false)}
            className="md:hidden text-gray-500 hover:text-white"
          >
            <X size={20} />
          </button>
        </div>

        {/* Scrollable List */}
        <div className="overflow-y-auto flex-1 p-2 space-y-2">
          {chapters.map((chap, idx) => (
            <button
              key={idx}
              onClick={() => {
                setActiveChapterIndex(idx);
                // 选中后在移动端自动关闭侧边栏
                if (window.innerWidth < 768) setShowSidebar(false);
              }}
              className={`w-full text-left p-3 rounded-lg text-sm transition-all flex items-start gap-2
                ${activeChapterIndex === idx 
                  ? 'bg-indigo-900/40 border border-indigo-500/30 text-indigo-200' 
                  : 'hover:bg-gray-800 text-gray-400 border border-transparent'}
              `}
            >
              <div className="mt-0.5 shrink-0">
                {chap.isGenerated ? <CheckCircle size={14} className="text-green-500" /> : <FileText size={14} />}
              </div>
              <div className="min-w-0">
                <div className="font-semibold truncate">第{chap.outline.chapterNumber}章: {chap.outline.title}</div>
                <div className="text-xs text-gray-500 mt-1 truncate">{chap.outline.coolPoint}</div>
              </div>
            </button>
          ))}
        </div>

        {/* Sidebar Footer: Add More Chapters */}
        <div className="p-3 border-t border-gray-800 bg-gray-900 shrink-0">
          <button
            onClick={onLoadMoreChapters}
            disabled={isLoadingMore}
            className="w-full py-2.5 rounded-lg border border-dashed border-gray-600 text-gray-400 hover:text-white hover:border-indigo-500 hover:bg-gray-800 transition-all flex items-center justify-center gap-2 text-sm font-medium"
          >
            {isLoadingMore ? (
              <>
                <Loader2 size={16} className="animate-spin" />
                推演中...
              </>
            ) : (
              <>
                <PlusCircle size={16} />
                续写后续5章大纲
              </>
            )}
          </button>
        </div>
      </div>

      {/* Main Content Area */}
      <div className="flex-1 flex flex-col h-full overflow-hidden relative bg-black/20">
        {/* Info Header */}
        <div className="p-4 border-b border-gray-800 bg-gray-850 flex justify-between items-start md:items-center flex-col md:flex-row gap-4 shrink-0">
          <div className="w-full md:w-auto">
             <h3 className="text-xs font-bold text-gray-500 uppercase tracking-wider mb-1">本章脉络 & 规则</h3>
             <p className="text-sm text-gray-300 line-clamp-2 md:line-clamp-1">
               <span className="text-indigo-400">[{activeChapter.outline.narrativePulse}]</span> {activeChapter.outline.rules.join(" | ")}
             </p>
          </div>

          <div className="flex items-center gap-3 self-end md:self-auto shrink-0">
            {/* Edit Toggle Button */}
            {(activeChapter.content || activeChapter.isGenerated) && !isGenerating && (
              <button
                onClick={() => setIsEditing(!isEditing)}
                className={`px-4 py-2 rounded-lg flex items-center gap-2 font-bold transition-all border text-sm md:text-base
                  ${isEditing 
                    ? 'bg-green-600/20 text-green-400 border-green-500/50 hover:bg-green-600/30' 
                    : 'bg-gray-800 hover:bg-gray-700 text-gray-300 border-gray-700'
                  }`}
              >
                {isEditing ? (
                  <>
                    <Save size={16} />
                    <span className="hidden sm:inline">完成</span>
                  </>
                ) : (
                  <>
                    <Edit size={16} />
                    <span className="hidden sm:inline">修改</span>
                  </>
                )}
              </button>
            )}

            {/* Generate Button */}
            {(!activeChapter.isGenerated && !activeChapter.content) && (
              <button
                onClick={handleGenerate}
                disabled={isGenerating}
                className="px-5 py-2 bg-indigo-600 hover:bg-indigo-500 text-white rounded-lg flex items-center gap-2 font-bold shadow-lg shadow-indigo-500/20 whitespace-nowrap text-sm md:text-base"
              >
                {isGenerating ? '创作中...' : '生成正文'}
                {!isGenerating && <Play size={16} fill="currentColor" />}
              </button>
            )}
          </div>
        </div>

        {/* Scrollable Reader / Editor */}
        <div className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-3xl mx-auto h-full">
             {isEditing ? (
               <div className="h-full min-h-[600px] bg-gray-900 p-4 md:p-8 rounded-xl border border-indigo-500/30 shadow-2xl flex flex-col animate-in fade-in duration-300">
                 <div className="mb-4 pb-4 border-b border-gray-800 flex flex-col gap-2">
                    <div className="flex justify-between items-center text-xs text-gray-500 uppercase tracking-wider font-bold">
                        <span>正在编辑: 第{activeChapter.outline.chapterNumber}章</span>
                        <span className={activeChapter.content.length > 2000 ? 'text-green-500' : 'text-gray-500'}>
                            {activeChapter.content.length} 字
                        </span>
                    </div>
                    <input 
                        type="text" 
                        value={activeChapter.outline.title}
                        onChange={(e) => onUpdateTitle(activeChapterIndex, e.target.value)}
                        className="bg-transparent text-xl md:text-2xl font-serif font-bold text-white border-b border-gray-700 focus:border-indigo-500 outline-none py-1 transition-colors placeholder-gray-700"
                        placeholder="输入章节标题..."
                    />
                 </div>
                 <textarea 
                   className="w-full flex-1 bg-transparent border-none outline-none text-gray-200 font-serif text-base md:text-lg leading-loose resize-none focus:ring-0"
                   value={activeChapter.content}
                   onChange={(e) => onUpdateChapter(activeChapterIndex, e.target.value, true)} 
                   placeholder="在此输入章节正文..."
                   spellCheck={false}
                   autoFocus
                 />
               </div>
             ) : (
               <>
                 <ChapterReader 
                   title={`第${activeChapter.outline.chapterNumber}章 ${activeChapter.outline.title}`}
                   content={activeChapter.content}
                   isStreaming={isGenerating && activeChapterIndex === chapters.findIndex(c => c === activeChapter)}
                 />

                 {/* Next Chapter Guide */}
                 {activeChapter.isGenerated && activeChapterIndex < chapters.length - 1 && (
                   <div className="mt-8 md:mt-12 text-center pb-8 md:pb-0">
                     <button
                       onClick={() => setActiveChapterIndex(prev => prev + 1)}
                       className="text-gray-400 hover:text-white underline decoration-indigo-500 underline-offset-4 py-4 px-8"
                     >
                       继续下一章
                     </button>
                   </div>
                 )}
               </>
             )}
          </div>
        </div>
      </div>
    </div>
  );
};

export default StepWriting;

// 角色定义
export interface Character {
  name: string;
  role: 'Protagonist' | 'Antagonist' | 'Support' | 'Mob';
  personality: string; // 性格特征
  background: string; // 背景故事
  goal: string; // 目标
  cheat?: string; // 金手指/特殊能力 (仅主角有)
}

// 世界观设定
export interface WorldSetting {
  theme: string; // 如：赛博修仙、末世重生
  powerSystem: string; // 力量体系
  rules: string; // 世界核心规则
}

// 故事大纲节点
export interface PlotPoint {
  phase: string; // 阶段：开篇、发展、高潮、结尾
  summary: string; // 剧情概括
}

// 章节细纲
export interface ChapterOutline {
  chapterNumber: number;
  title: string;
  summary: string; // 故事梗概
  narrativePulse: string; // 叙事脉络
  coolPoint: string; // 本章爽点 (Cool Point)
  rules: string[]; // 必须遵守的规则/限制
}

// 章节正文
export interface ChapterContent {
  outline: ChapterOutline;
  content: string; // 生成的正文内容
  isGenerated: boolean;
}

